1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./scenario.js";
3	
4	describe("Scenario Runner", () => {
5	  // 1. Single quote step → one {premium}, using yearsWithMHPCO and isFollowUp=false
6	  it.todo("should return one premium result for a single quote step using yearsWithMHPCO and isFollowUp=false");
7	
8	  // 2. Multiple quotes: first isFollowUp=false, every subsequent isFollowUp=true
9	  it.todo("should treat the first quote as not a follow-up and every subsequent quote as a follow-up");
10	
11	  // 3. Claim references a quote step by zero-based policy index; result is {payout, remainingCap}
12	  it.todo("should resolve a claim's policy from the referenced quote step and return payout and remainingCap");
13	
14	  // 4. Successive claims on the same policy share the cap
15	  it.todo("should start a second claim on the same policy from the remainingCap left by the first claim");
16	
17	  // 5. Results preserve order and length of steps (interleaved quote/claim)
18	  it.todo("should return results in the same order and length as the steps");
19	
20	  // 6. Schema example end-to-end
21	  it.todo("should produce premium then payout/remainingCap for the prompt's schema example");
22	});
